document.getElementById("current-year").textContent=new Date().getFullYear();document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const t=this.getAttribute("href");if("#"===t)return;const a=document.querySelector(t);a&&window.scrollTo({top:a.offsetTop-100,behavior:"smooth"})})});document.querySelectorAll(".faq-question").forEach(e=>{e.addEventListener("click",function(){const e=this.nextElementSibling,t=this.classList.contains("active");document.querySelectorAll(".faq-question").forEach(e=>{e.classList.remove("active"),e.setAttribute("aria-expanded","false"),e.nextElementSibling.classList.remove("active")}),t||(this.classList.add("active"),this.setAttribute("aria-expanded","true"),e.classList.add("active"))})});
